function updateSeo(lang){
  const seo=SEO_META[lang]||SEO_META.ar;
  document.title=seo.title;
  const set=(selector,value)=>{const el=document.querySelector(selector); if(el) el.setAttribute('content',value);};
  set('meta[name="description"]',seo.description);
  set('meta[property="og:title"]',seo.title);
  set('meta[property="og:description"]',seo.description);
  set('meta[name="twitter:title"]',seo.title);
  set('meta[name="twitter:description"]',seo.description);
}
const RTL=new Set(['ar']);
function preferredLang(){const p=new URLSearchParams(location.search);const q=p.get('lang');if(q&&I18N[q])return q;const saved=localStorage.getItem('alogo_lang');if(saved&&I18N[saved])return saved;const nav=(navigator.language||'ar').slice(0,2);return I18N[nav]?nav:'ar'}
function setLang(lang){if(!I18N[lang]) lang='ar';localStorage.setItem('alogo_lang',lang);document.documentElement.lang=lang;document.documentElement.dir=RTL.has(lang)?'rtl':'ltr';const langSelect=document.getElementById('lang');if(langSelect)langSelect.value=lang;document.querySelectorAll('[data-i18n]').forEach(el=>{const key=el.dataset.i18n;if(I18N[lang][key]) el.innerHTML=I18N[lang][key]});document.querySelectorAll('[data-i18n-content]').forEach(el=>{const key=el.dataset.i18nContent;if(I18N[lang][key]) el.setAttribute('content',I18N[lang][key])});const park=document.querySelector('[data-map-label="park"]'); if(park) park.textContent = lang==='ar'?'حديقة الزهراء':'Al Zahra Park';updateSeo(lang);}
setLang(preferredLang());
const langSelect=document.getElementById('lang');if(langSelect)langSelect.addEventListener('change',e=>setLang(e.target.value));
const menu=document.getElementById('menuBtn'),nav=document.getElementById('nav');function closeMenu(){if(!nav||!menu)return;nav.classList.remove('open');document.body.classList.remove('menu-open');menu.setAttribute('aria-expanded','false')}
if(menu&&nav){menu.addEventListener('click',()=>{const open=nav.classList.toggle('open');document.body.classList.toggle('menu-open',open);menu.setAttribute('aria-expanded',open?'true':'false')});nav.querySelectorAll('a').forEach(a=>a.addEventListener('click',closeMenu));document.addEventListener('click',e=>{if(document.body.classList.contains('menu-open')&&!e.target.closest('.header'))closeMenu()});window.addEventListener('scroll',()=>{if(document.body.classList.contains('menu-open'))closeMenu()},{passive:true});}
if('IntersectionObserver' in window){const io=new IntersectionObserver(entries=>entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('show')}),{threshold:.08});document.querySelectorAll('.reveal').forEach(el=>io.observe(el));}else{document.querySelectorAll('.reveal').forEach(el=>el.classList.add('show'));}
